import React from 'react';
import { hirRouteNames } from "./routeNames";
import {connect} from 'react-redux';
import { Router, Switch, Route} from 'react-router-dom';
import { 
    headerActions, headerStrings, screenActions,  mainStageAction, 
    MySnackbar, SnackDialog, mainStageHeaderAction,  mainStageStrings, breadCrumbActions
} from './utils';
import { PrivateRoutePlane, LogoutRoute } from './RouteTemplates';
import { history } from '../../helpers';
import { hirMenuItem } from './menuItems';
import { hirUtilActions, theme1, hirUtil, hirUtilStrings, hirActions } from './utils';
import { FormLabel, LinearProgress, ThemeProvider, withStyles } from '@material-ui/core';
import { hirRoutes } from './routes';
import Login, { HIRLogin } from './HIRLogin/HIRLogin';
import $ from 'jquery';
import { DrawerHeader } from './Includes';
import { withTheme } from '@material-ui/core';
import { HIRSettingConfig } from './HIRSettings/HIRSettingConfig';


const styles = theme => ({
    mainStage : {
        margin : 0,
        padding : 0,
    },
})
class _HIRApp extends React.PureComponent{
    constructor(props) {
        super(props);
        const {pathname} = history.location;
        this.state = {
            loadingProfile : true
        }
        const {
            dispatch,
        } = props;
        hirUtilActions({
            [hirUtilStrings.theme] : theme1,
            [hirUtilStrings.tokenAlias] : "hirToken",
            [hirUtilStrings.userAlias] : "hirUserId",
            [hirUtilStrings.userType] : "hirType",
            // [hirUtilStrings.backendUrl] : "http://localhost:8003/api/v1/hir/", 
            // [hirUtilStrings.backendBaseUrl] : "http://localhost:8003",
            [hirUtilStrings.backendUrl] : "/api/v1/hir/", 
            [hirUtilStrings.backendBaseUrl] : "",
            [hirUtilStrings.defaultImage] : "/image/default.png",
        })(dispatch);
        headerActions({
            [headerStrings.headerTitle] : "HEALTH RECORDS",
            [headerStrings.headerTitleProps] : {
                style : {
                    borderBottom : "none",
                    color : hirUtil.getTheme().white,
                }
            },
            [headerStrings.drawer] : true,
            [headerStrings.visible] : true,
            [headerStrings.menuItems] : hirMenuItem,
            [headerStrings.drawerHeader] : DrawerHeader
        })(dispatch);
        screenActions.setTheme(theme1)(dispatch);
        mainStageAction({
            [mainStageStrings.containerProps] : {
                style : {
                    margin : 0,
                    padding : "0px 10px 0px 20px",
                }
            }
        })(dispatch);
        breadCrumbActions.setProps({
            style : {
                borderBottom : "solid 1px " + theme1.primary,
                marginBottom : 10
            }
        })(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderAction.visible] : false,
        })(dispatch);               
    }
    componentDidMount(){
        $("title").text("Medical Records");
        this.getUser();
    }
    static getDerivedStateFromProps(props, state){
        const {
            dispatch, 
            [hirUtilStrings.myProfile] : myProfile
        } = props;
        if(myProfile && hirUtil.isLogedIn())
            state.loadingProfile = false;
    }
    getUser(){
        const {
            dispatch, 
            [hirUtilStrings.myProfile] : myProfile
        } = this.props;
        if(hirUtil.isLogedIn()){
            if(!myProfile){
                hirActions.getUser(done => {
                    done && this.setState({loadingProfile : false})
                })(dispatch);
            }else this.setState({loadingProfile : false})
        }else {
            history.replace(hirRouteNames.login);
        }
    }
    render(){
        const {classes} = this.props,
        {loadingProfile} = this.state;
        let appTheme = this.props.theme;
        if(theme1) appTheme = {
            ...appTheme, 
            colors : theme1
        }
        return(
            <Router history={history}>
                <ThemeProvider theme={appTheme}>
                    <React.Suspense
                        fallback={<div>Loading...</div>}>
                        <Switch>
                            {hirRoutes && hirRoutes.map((route, index)=>{
                                return <PrivateRoutePlane 
                                    loadingProfile={loadingProfile} 
                                    theme={theme1} {...route} key={index}/>
                            })}
                            <Route path={hirRouteNames.login} exact component={props=><HIRLogin {...props}/>}/>
                            <LogoutRoute path={hirRouteNames.logout}/>
                        </Switch>
                    </React.Suspense>
                    <MySnackbar/>
                    <SnackDialog/>
                    {hirUtil.isAdmin() && <HIRSettingConfig/>}
                </ThemeProvider>
            </Router>
        )
    }
}
const mapStateToProps = ({hirUtilReducer}) => ({
    [hirUtilStrings.myProfile] : hirUtilReducer[hirUtilStrings.myProfile],
})
export const HIRApp =  connect(mapStateToProps)(withStyles(styles)(withTheme(_HIRApp)));
export {HIRApp as default};