import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { MyListCard } from '../MyListCard/MyListCard';
import { Button, Menu } from '@material-ui/core';
const style = theme => ({
    root: {
        
    }
})
class _MyListCardMenuPopup extends Component {
    constructor(props) {
        super(props);
        this.state={
            anchorEl : null,
        }
    }
    menuBtnHandler=e=>{
        const target = e.target;
        this.setState(state=>({anchorEl : state.anchorEl ? null : target}))
    }
    listItemClick = (item, index) => {
        this.setState({anchorEl :null});
        const {listItemClick} = this.props.myListCardProps;
        if(listItemClick) listItemClick(item,index);
    }
    finishBtnAction = () => {
        this.setState({anchorEl: null});
        const {finishBtnAction} = this.props.myListCardProps || {};
        if(finishBtnAction) finishBtnAction();
    }
    render() {
        const {
            classes, myListCardProps, menuBtnValueDisplay,
        } = this.props;
        const {finishBtnAction,listItemClick, listItemComponent, ...listCardProps} = myListCardProps;
        const {
            anchorEl, selections
        } = this.state;
        return (
            <div className={classes.root}>
                <Button 
                    classes={{
                        label : classes.subjectBtnString
                    }}
                    onClick={this.menuBtnHandler.bind(this)}>
                    {menuBtnValueDisplay ? menuBtnValueDisplay(selections) : "selects"}
                </Button>
                <Menu
                    open={Boolean(anchorEl)}
                    anchorEl={anchorEl}
                    onClose={e => this.setState({anchorEl : null})}
                    >
                    <MyListCard     
                        elevation={0}                   
                        {...listCardProps}
                        listItemClick={this.listItemClick.bind(this)}
                        finishBtnAction={this.finishBtnAction.bind(this)}
                        component={listItemComponent && listItemComponent(selections)}
                        />
                </Menu>
            </div>
        );
    }
}
_MyListCardMenuPopup.propTypes = {
    classes : PropTypes.object.isRequired,
    myListCardProps : PropTypes.object,
    menuBtnValueDisplay : PropTypes.func,
    searchOnChange : PropTypes.func,
};
export const MyListCardMenuPopup = withStyles(style)(_MyListCardMenuPopup);