import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Stepper, Step, StepLabel, Button, IconButton, withWidth } from '@material-ui/core';
import { ArrowForwardIos, ArrowBackIos } from '@material-ui/icons';
const style = theme => ({
    root: {
        
    },
    btnContainer : {
        display : 'flex',
        alignItems : "center",
    },
    grow : {
        display : "flex",
        flexGrow : 1,
    },
    bBtn : {},
    fBtn : {},
    vBtnContainer : {
        display : "flex",
        justifyContent : "center",
    }
})
class _MySimpleStepper extends Component {
    constructor(props) {
        super(props);
        this.state = {
            activeStep : 0
        }
        const {getContext, activeStepChangeCallback} = props;
        if(getContext) getContext(this)
        if(activeStepChangeCallback) activeStepChangeCallback(this.state.activeStep);
    }
    prevButton(){
        const {classes, navigatorPrevBtnDisabled} = this.props;
        const {activeStep} = this.state;
        return <IconButton
        disabled={navigatorPrevBtnDisabled || activeStep === 0}
        onClick={this.adjustStep(false)}>
            <ArrowBackIos color="secondary" className={classes.bBtn}/>
        </IconButton>
    }
    nextButton(){
        const {
            classes, finishBtn : FinishBtn, stepLabels,
            navigatorNextBtnDisabled
        } = this.props;
        const {activeStep} = this.state;
        return <IconButton
        disabled={navigatorNextBtnDisabled || (stepLabels && activeStep === stepLabels.length - 1)}
        onClick={this.adjustStep(true)}>
            {stepLabels && FinishBtn && activeStep === stepLabels.length - 1 ? 
                <FinishBtn/> : 
                <ArrowForwardIos color="primary" className={classes.fBtn}/>
            }
        </IconButton>
    }
    adjustStep = (forward) => () => {
        let {activeStep} = this.state;
        const initialActiveStep = activeStep;
        const {activeStepChangeCallback} = this.props;
        if(forward) activeStep++;
        else activeStep--;
        this.setState({activeStep});
        if(activeStepChangeCallback) activeStepChangeCallback(activeStep, (success)=>{
            if(!success) this.setState({activeStep : initialActiveStep});
        });
    }
    render() {
        const {
            classes, stepLabels, stepProps, navigator, 
            activeStepChangeCallback, width, stepperProps
        } = this.props;
        const PrevButton = this.prevButton.bind(this);
        const NextButton = this.nextButton.bind(this);
        let activeStep; 
        if(navigator){
            activeStep = this.state.activeStep;
            if(!activeStepChangeCallback)
                console.trace("Use of navigator requires activeStepChangeCallback, but got "+activeStepChangeCallback);
        }else activeStep = this.props.activeStep;
        const {alternativeLabel, ...otherStepperProps} = stepperProps || {};
        return (
            <div className={classes.root}>                
                <div className={classes.btnContainer}>
                    {["md", "lg"].indexOf(width) !== -1 && navigator && 
                    <div className={classes.btnContainer}>
                        <PrevButton/>
                    </div>}
                    <Stepper 
                        orientation={["md", "lg"].indexOf(width) !== -1 ? "horizontal" : "vertical"}
                        className={classes.grow} 
                        activeStep={activeStep}
                        alternativeLabel={["md", "lg"].indexOf(width) !== -1 ? true : false}
                        {...otherStepperProps}>
                        {stepLabels && stepLabels.map((label, index)=>{
                            const {stepLabelProps, ...sProps} = stepProps && stepProps[index] ? stepProps[index] : {};
                            return <Step 
                                {...this.props.commonStepProps} 
                                {...sProps} 
                                key={index}>
                                <StepLabel 
                                    {...this.props.commonStepLabelProps}
                                    {...stepLabelProps}>{label}</StepLabel>
                            </Step>
                        })}
                    </Stepper>
                    {["md", "lg"].indexOf(width) !== -1 && navigator && 
                    <div className={classes.btnContainer}>
                        <NextButton/>
                    </div>}
                </div>
                {["md", "lg"].indexOf(width) === -1 && <div className={classes.vBtnContainer}>
                    <PrevButton/>
                    <NextButton/>
                </div>}
            </div>
        );
    }
}
_MySimpleStepper.propTypes = {
    classes : PropTypes.object.isRequired,
    stepLabels : PropTypes.array,
    activeStep : PropTypes.number,
    stepProps : PropTypes.array,
    stepperProps : PropTypes.shape({
        ...Stepper.propTypes, 
        stepLabelProps : PropTypes.shape(StepLabel.propTypes)
    }),
    commonStepProps : PropTypes.shape(Step.propTypes),
    commonStepLabelProps : PropTypes.shape(StepLabel.propTypes),
    navigator : PropTypes.bool,
    navigatorPrevBtnDisabled : PropTypes.bool,
    navigatorNextBtnDisabled : PropTypes.bool,
    activeStepChangeCallback : PropTypes.func,
    getContext : PropTypes.func,
    finishBtn : PropTypes.func,

};
export const MySimpleStepper = withStyles(style)(withWidth()(_MySimpleStepper));