export const hookStateVisibility = (vis, data) => {
    if(vis && vis.variables && vis.variables.state){
        let {name : stateVarName, value : stateValue} = vis.variables.state;
        if(typeof stateValue === "string"){
            if(data &&  data[stateVarName] && data[stateVarName] !== stateValue)
                return false;
        }else if(Array.isArray(stateValue)){
            if(data &&  data[stateVarName] && 
                stateValue.indexOf(data[stateVarName]) === -1){
                return false;
            }
        }
    }
    return true;
}
export const hookForeignOnChange = (hook, data, hookOption) => {
    if(hook && hook.foreignOnChangeMap){
        const onChangeMap = hook.foreignOnChangeMap;
        if(onChangeMap.variables && onChangeMap.variables.state){
            let {name : stateVarName, map} = onChangeMap.variables.state;
            if(data && data[stateVarName] && hookOption && hookOption.foreignItem){
                const options = hookOption.foreignItem.options;
                if(options){
                    const selectedOption = options.find(item=>item._id===data[stateVarName]);
                    if(selectedOption){
                        const {foreignField} = map;
                        map.result = selectedOption[foreignField]
                        return map;
                    }
                }
            }
        }
    }
    return null;
}
export const getFormDisplayData = (formDisplayContext, callback) => notify => {
    let newData = {};
    const {inputFieldContexes} = formDisplayContext;
    for (const name in inputFieldContexes) {
        if (inputFieldContexes.hasOwnProperty(name)) {
            const context = inputFieldContexes[name];
            const data = {...context.state.data};
            if(callback && !callback(name, data[name], context))
                return false;
            else{
                if(data[name])
                    newData[name] = data[name];
                else if(notify && !notify("Empty field", "error")){
                    return false;
                }
            }
        }
    }
    return newData;
}
export const resetFormDisplayData = (formDisplayCotext, callback) => {
    if(formDisplayCotext && formDisplayCotext.inputFieldContexes){
        const formFieldContexes = formDisplayCotext.inputFieldContexes;
        for (const name in formFieldContexes) {
            if (formFieldContexes.hasOwnProperty(name)) {
                const context = formFieldContexes[name];
                context && context.setState({data : {}})
            }
        }
        if(callback) callback();
    } 
}