export const protoSetup = () => {
    Array.prototype.getFirstObjectByPropValue = function(objProp, objValue){
        for (let i = 0; i < this.length; i++) {
            const obj = this[i];
            if(obj[objProp] && obj[objProp] === objValue)
                return { item: obj, index : i};
        }
        return null;
    }
    Array.prototype.getFirstObjectWithProp = function(prop){
        for (let i = 0; i < this.length; i++) {
            const obj = this[i];
            if(obj.hasOwnProperty(prop))
                return { item: obj, index : i};
        }
        return null;
    }

    //in use
    Array.prototype.removeObjectWithProp = function(prop){
        for (let i = 0; i < this.length; i++) {
            const obj = this[i];
            if(obj.hasOwnProperty(prop)){
                this.splice(i, 1);
                i--;
            }
        }
    }
}
export const compareValues = function(key, order='asc') {
    return function(a, b) {
        if(!a.hasOwnProperty(key) || !b.hasOwnProperty(key)) {
            // property doesn't exist on either object
            return 0;
        }

        const varA = (typeof a[key] === 'string') ?
        a[key].toUpperCase() : a[key];
        const varB = (typeof b[key] === 'string') ?
        b[key].toUpperCase() : b[key];

        let comparison = 0;
        if (varA > varB) {
            comparison = 1;
        } else if (varA < varB) {
            comparison = -1;
        }
        return (
            (order == 'desc') ? (comparison * -1) : comparison
        );
    };
}
export const scorePositionLiteral = (position) => {
    if(!position) return null;
    try{
        const lastInt = parseInt(String(position).substr(-1, 1));
        switch(lastInt){
            case 1 : return position + "st";
            case 2 : return position + "nd";
            case 3 : return position + "rd";
            default : return position + "th";
        }
    }catch(e){
        console.error("$$scorePositionLiteral ---- CONVERSION ERROR");
    }
}
export const copyToClipboard = (text, keepTabs) => {
    let input;
    if(keepTabs) {
        input = document.createElement("textarea");
        input.innerHMTL = text;
    }else{
        input = document.createElement("input");
        input.setAttribute("value", text);
    }
    document.body.appendChild(input);
    input.select();
    var result = document.execCommand("copy");
    document.body.removeChild(input);
    return result;
}