import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';


const style = theme => ({
    root: {
        marginTop : 20,
        fontSize : 12,
    }
})
class _MyArticleDisplayContent extends Component {
    render() {
        const {classes, content} = this.props;
        return (
            <div className={classes.root}>
                {content}
            </div>
        );
    }
}


_MyArticleDisplayContent.propTypes = {
    classes : PropTypes.object.isRequired,
     content : PropTypes.string,
};
export const MyArticleDisplayContent = withStyles(style)(_MyArticleDisplayContent);
export {MyArticleDisplayContent as default}