import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { MenuItem, TextField, FormControl } from '@material-ui/core';
const style = theme => ({
    root: {
        position : "relative"
    },
    dropdown : {
        borderRadius : 10,
        position : "absolute",
        width : "100%",
        zIndex : 100,
        maxHeight : 200,
        overflow : "scroll",
        background : "black",
        color : "white"
    },
    listItem : {
        fontSize : 12,
    },
    notchedOutline : {
        borderColor : "white"
    }
})
class _TextFieldDropdown extends Component {
    state = {
        text : ""
    }
    onChange(e){
        const value = e.target.value;
        const {onTextChange} = this.props;
        if(onTextChange) onTextChange(value);
    }
    onMenuClick = item => () => {
        const {onSelect} = this.props;
        if(onSelect) onSelect(item);
    }
    render() {
        const {classes,itemDisplay} = this.props;
        const {list} = this.props;
        return (
            <div className={classes.root}>
                    <TextField
                        fullWidth
                        variant="outlined"
                        margin="dense"
                        onChange={this.onChange.bind(this)}
                        {...this.props.textFieldProps}
                    />
                {list && <div className={classes.dropdown}>
                    {list.map((item, index)=>
                        <MenuItem className={classes.listItem} key={index} onClick={this.onMenuClick(item)}>
                            {itemDisplay ? itemDisplay(item) :  item.name}
                        </MenuItem>
                    )}
                </div>}
            </div>
        );
    }
}
_TextFieldDropdown.propTypes = {
    classes : PropTypes.object.isRequired,
    onTextChange : PropTypes.func,
    textFieldProps : PropTypes.shape(TextField.propTypes),
    list : PropTypes.array,
    itemDisplay : PropTypes.func,
    onSelect : PropTypes.func,
};
export const TextFieldDropdown = withStyles(style)(_TextFieldDropdown);