import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { FormDisplay } from '../FormDisplay';
import { inputTypes } from './inputTypes';
import { Button } from '@material-ui/core';
import { MyDialog } from '../../MyDialog';
import { OptionCreator } from './OptionCreator';
import { MyTable, EditableCellMapFormat } from '../../MyTable';
const style = theme => ({
    root: {
        
    },
    controllerContainer : {
        
    },
    controllerInputContainer : {
        display : "flex",
        flexDirection : "row"
    },
    footerContainer : {
        display : "flex",
        flex : 1,
        justifyContent : "center",
        alignItems : "center",
    }
})
class _FormController extends Component {
    constructor(props) {
        super(props);
        this.state = {
            formConfig : props.formConfig || [],
            optionDialog : false,
            options : null
        }
        this.handleInput = this.handleInput.bind(this);
        const {getContext} = props;
        if(getContext) getContext(this);
    }
    getFormDisplayContext = context => this.formDisplayContext = context;
    handleInput(name, value){
        switch(name){
            case "type" : 
                switch(value) {
                    case inputTypes.select:
                    case inputTypes.check :
                    case inputTypes.radio : 
                        return this.setState({optionDialog: true, optionInfo : {name, value}});
                    default : return null;
                }; break;
            default : return null;
        }
    }
    addField = () => {
        const {options} = this.state;
        const formConfig = this.state.formConfig ? [...this.state.formConfig] : [];
        let newData = {};
        const {inputFieldContexes} = this.formDisplayContext;
        for (const name in inputFieldContexes) {
            if (inputFieldContexes.hasOwnProperty(name)) {
                const context = inputFieldContexes[name];
                const data = {...context.state.data};
                context.setState({data : {}});
                newData[name] = data[name];
                if(name === "type" && [inputTypes.select, inputTypes.check, inputTypes.radio].indexOf(newData[name]) !== -1){
                    newData.options = options;
                }
            }
        }
        formConfig.push(newData);
        this.setState({formConfig, options : null});
    }
    onOptionsFinishCallback(options){
        this.setState({options, optionDialog : false})
    }
    CellMapWrapper = superProps => props => <EditableCellMapFormat {...props} {...superProps}/>
    deleteBtnHandler = row => () => {
        const {formConfig:old} = this.state;
        let formConfig = old ? [...old] : [];
        const {item, index} = formConfig.getFirstObjectByPropValue("name", row.name) || {};
        if(item){
            formConfig.splice(index, 1);
        } 
        this.setState({formConfig});
    }
    render() {
        const {classes, footer : Footer} = this.props;
        const {formConfig, optionDialog} = this.state;
        let configEditable = [...formConfig];
        configEditable = configEditable.map(item=>({...item, delible : true}));
        return (
            <div className={classes.root}>
                <FormDisplay
                    formName="formDisplay"
                    formConfig={formConfig}
                    {...this.props.formDisplayProps}
                    />
                <MyTable
                    header={["Name", "Label", "Placeholder", "Type", "Required", "Actions"]}
                    dataMap={["name", "label", "placeholder", "type", "required", "action"]}
                    data={configEditable}
                    CellMap={this.CellMapWrapper({
                        deleteBtnHandler: this.deleteBtnHandler.bind(this),
                    })}
                    />
                <div className={classes.controllerContainer}>
                    <FormDisplay
                        formName="formController"
                        getContext={this.getFormDisplayContext.bind(this)}
                        controller={true}
                        inputFieldProps={{
                            handleChecked : this.handleInput,
                            onTextChange : this.handleInput,
                            fieldProps : {
                                variant : "outlined"
                            },
                            itemContainerProps : {
                                style : {
                                    margin : 5,
                                }
                            }
                        }}
                        containerProps={{
                            className : classes.controllerInputContainer
                        }}
                        formConfig={[
                            {name : "name", placeholder : "Name", label : "Name"},
                            {name : "label", placeholder : "Label", label : "Label"},
                            {name : "placeholder", placeholder : "Placeholder", label : "Placeholder"},
                            {
                                name : "type", placeholder : "Input type", label : "Input Type",
                                type :"select", options : Object.entries(inputTypes).map(
                                    (item, index)=>({_id : item[0], name : item[1]})
                                )
                            },
                            {name : "required", label : "Required", type : "switch"},
                        ]}
                        footer={context=><div className={classes.footerContainer}>
                            <Button variant="contained" color="primary" onClick={this.addField.bind(this)}>Add Field</Button>
                        </div>}
                    />
                    <MyDialog open={optionDialog}>
                        <OptionCreator
                            onCancelClick={()=>this.setState({optionDialog: false})}
                            onFinishCallback={this.onOptionsFinishCallback.bind(this)}
                            errorHandler={this.props.notify}
                            />
                    </MyDialog>
                </div>
            {Footer && <Footer context={this}/>}
            </div>
        );
    }
}
_FormController.propTypes = {
    classes : PropTypes.object.isRequired,
    formConfig : PropTypes.array,
    formDisplayProps : PropTypes.shape(
        FormDisplay.propTypes
    ),
    footer : PropTypes.func,
    notify : PropTypes.func,
};
export const FormController = withStyles(style)(_FormController);