import React, { Component, Fragment } from 'react'
import PropTypes from 'prop-types';
import {connect} from "react-redux";
import { 
    FormControl, TextField, Checkbox, FormHelperText, 
    FormControlLabel, Switch, MenuItem, OutlinedInput, Select, 
    InputLabel, withStyles, FormLabel, RadioGroup, Radio } from '@material-ui/core';
import classNames from 'classnames';
import { hookStateVisibility, hookForeignOnChange } from '../functions';
import { formStrings } from '../../config';
import { formActions } from '../../actions';

const styles = theme => ({
    root : {

    },
    select : {
        minWidth : 100
    },
    textarea : {
        
    }
})


class _InputFields extends Component {
    constructor(props) {
        super(props);
        const {getContext, element, formName, value} = props;
        this.state = {
            data : {
                [element.name] : value
            }
        }
        this.formName = formName;
        if(getContext) getContext(element.name, this);
    }
    
    onTextChange=(name, type)=>e=>{
        let value = e.target.value, file;
        const { controller } = this.props;
        if(controller && name === "name") value = String(value).split(" ").join("").toLowerCase();
        const data = {...this.state.data};
        if(type === "file"){
            file = e.target.files && e.target.files[0];
            data["_"+name] = value;
            data[name] = file;
        }else data[name] = value;
        this.setState({data});
        // const {onTextChange} = this.props;
        // if(onTextChange) onTextChange(name, value);
        formActions.setFormData(this.formName, name, data[name])(this.props.dispatch);
    }
    handleSingleChecked = name => e => {
        const checked = e.target.checked;
        let data = {...this.state.data} || {};
        data[name] = checked;
        this.setState({data});
        formActions.setFormData(this.formName, name, data[name])(this.props.dispatch);
    }
    handleChecked=(name, value)=>e=>{
        const checked = e.target.checked;
        let data = {...this.state.data} || {};
        if(checked){
            data[name] ? data[name].push(value) : data[name] = [value];
        }else{
            data[name].splice(data[name].indexOf(value), 1);
        }
        this.setState({data});
        formActions.setFormData(this.formName, name, data[name])(this.props.dispatch);
        // const {handleChecked} = this.props;
        // if(handleChecked) handleChecked(name, data[name]);
    }
    handleRadio = name => e => {
        const value = e.target.value;
        let data = {...this.state.data} || {};
        data[name] = value;
        this.setState({data});
        formActions.setFormData(this.formName, name, value)(this.props.dispatch);
    }
    render() {
        const {
            classes,
            [formStrings.forms] : forms,
            element,
        } = this.props;
        let {className, name, type, description, ...props} = this.props.element;
        const {data} = this.state;
        const namedFieldProps = this.props.namedFieldProps && this.props.namedFieldProps[element.name] ? this.props.namedFieldProps[element.name] : {};
        if(!hookStateVisibility(
            this.props.hooks && this.props.hooks.visibility, 
            forms && forms[this.formName]
        )) return null;
        switch(type){
            case "select" : 
                let options = this.props.element.options
                if(this.props.hooks && this.props.hooks.foreignOnChangeMap){
                    const changeResult = hookForeignOnChange(
                        this.props.hooks,
                        forms && forms[this.formName],
                        this.props.hookOptions
                    )
                    if(changeResult) options = changeResult.result;
                }
                return <FormControl fullWidth {...this.props.itemContainerProps}>
                    <InputLabel {...this.props.labelProps} htmlFor="inputType">{this.props.element.label}</InputLabel>
                    <Select
                        className={classes.select}
                        variant="filled"
                        value={data[name] || (this.props.element.default || "")}
                        input={<OutlinedInput id="inputType" name="inputType" labelWidth={100}/>}
                        onChange={this.onTextChange(name)}
                        {...this.props.fieldProps}>
                            {options && options.map((item, i)=>{
                                return <MenuItem key={"select"+i+"-"+this.props.index} 
                                    value={item._id}>{item.name}</MenuItem>
                            })}
                    </Select>
                    <FormHelperText {...this.props.fieldDescriptionProps}>{description}</FormHelperText>
                </FormControl>
            case "check" : return <FormControl fullWidth {...this.props.itemContainerProps}>
                    {this.props.element.options ? 
                        <Fragment>
                            <FormLabel {...this.props.labelProps}>{this.props.element.label}</FormLabel>
                            {this.props.element.options.map((item, index)=>{
                                return <FormControlLabel
                                    key={index}
                                    label={item.name}
                                    {...namedFieldProps}
                                    control={<Checkbox
                                        checked={data[name] ? data[name].indexOf(item._id) !== -1 : false}
                                        onChange={this.handleChecked(name, item._id)}
                                        {...this.props.fieldProps}/>}/>
                            })}
                        </Fragment>:
                        <FormControlLabel
                            label={this.props.element.label}
                            control={<Checkbox
                                checked={data[name] || false}
                                onChange={this.handleSingleChecked(name)}
                                {...this.props.fieldProps}/>}/>
                        }
                    <FormHelperText {...this.props.fieldDescriptionProps}>{description}</FormHelperText>
                </FormControl>;
            case "radio" : return <FormControl fullWidth {...this.props.itemContainerProps}>
                    <Fragment>
                        <FormLabel {...this.props.labelProps}>{this.props.element.label}</FormLabel>
                        <RadioGroup
                            onChange={this.handleRadio(name)}
                            value={data[name] || ""}
                            name={name}
                            aria-label={name}
                            {...this.props.radioGroupProps}
                        >
                            {this.props.element.options.map((item, index)=>{
                                return <FormControlLabel
                                key={index}
                                label={<span {...this.props.labelProps}>{item.name}</span>}
                                value={item._id}
                                control={<Radio size="small"/>}/>
                            })}
                        </RadioGroup>
                    </Fragment>
                    <FormHelperText {...this.props.fieldDescriptionProps}>{description}</FormHelperText>
                </FormControl>;
            case "textArea" : return <FormControl fullWidth {...this.props.itemContainerProps}>
                <TextField
                    value={data[name] || ""}
                    multiline
                    rows={4}
                    rowsMax={5}
                    label={this.props.element.label}
                    placeholder={this.props.element.placeholder2}
                    onChange={this.onTextChange(name)}
                    className={classNames(this.props.classes && this.props.classes.textarea, className)}
                    {...this.props.fieldProps}
                    />
                </FormControl>;
            case "switch" :  return <FormControl fullWidth {...this.props.itemContainerProps}>
                <FormControlLabel
                    label={this.props.element.label}
                    control={<Switch 
                        checked={data[name] || false}
                        onChange={this.handleSingleChecked(name)}
                        {...this.props.fieldProps}/>}
                    />
                <FormHelperText {...this.props.fieldDescriptionProps}>{description}</FormHelperText>
            </FormControl>;
            case "file" : 
                let fileProps = {...this.props.textFieldProps, ...props};
                return <FormControl fullWidth {...this.props.itemContainerProps}>
                    <TextField
                        type={type}
                        value={data["_"+name] || ""}
                        onChange={this.onTextChange(name, type)}
                        className={classNames(this.props.classes && this.props.classes.texfField, className)}
                        {...this.props.fieldProps}
                        {...fileProps}
                        />
                    <FormHelperText {...this.props.fieldDescriptionProps}>{description}</FormHelperText>
                </FormControl> ;
            default : 
                let mainProps = {...this.props.textFieldProps, ...props};
                return <FormControl fullWidth {...this.props.itemContainerProps}>
                    {name === "amount" && <FormHelperText>{Number(data[name]).toLocaleString()}</FormHelperText>}
                    <TextField
                        value={data[name] || ""}
                        type={type}
                        onChange={this.onTextChange(name, type)}
                        className={classNames(this.props.classes && this.props.classes.texfField, className)}
                        {...this.props.fieldProps}
                        {...mainProps}
                        />
                    <FormHelperText {...this.props.fieldDescriptionProps}>{description}</FormHelperText>
                </FormControl> ;
        }
    }
}
_InputFields.propTypes = {
    getContext : PropTypes.func,
    element : PropTypes.object.isRequired,
    fieldDescriptionProps : PropTypes.object,
    fieldProps : PropTypes.object,
    namedFieldProps : PropTypes.object,
    labelProps : PropTypes.object,
    optionProps : PropTypes.object,
    textAreaProps : PropTypes.object,
    radioGroupProps : PropTypes.object,
    onTextChange : PropTypes.func,
    handleChecked : PropTypes.func,
    data : PropTypes.object,                //this is the data value of the fields
    itemContainerProps : PropTypes.object,
    fieldDescriptionProps : PropTypes.object,
    element : PropTypes.object,
    hooks : PropTypes.object,
    formName : PropTypes.string,
    value : PropTypes.any,
    controller : PropTypes.bool,
}
const mapStateToProps = ({formReducer}) => ({
    [formStrings.forms] : formReducer[formStrings.forms],
})
export const InputFields = connect(mapStateToProps)(withStyles(styles)(_InputFields));
export {InputFields as default};