import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {connect} from 'react-redux';
import { FormLabel } from '@material-ui/core';
import { FormDisplay, getFormDisplayData } from '../../utils';
import { HIRButton } from '../../Includes';
import { appActions, alertAction } from '../../../../actions';
const style = theme => ({
    root: {
        
    }
})
class _HIRNewFamily extends Component {
    state = {
        loading : false
    }
    onClick(){
        const {dispatch, createRecord, editRecord, editMode} = this.props;
        this.setState({loading : true})
        const data = getFormDisplayData(this.newFamilyFormContext)((message, type)=>{
            appActions.showSnackbar(
                alertAction[type](message)
            )(dispatch)
        })
        if(data){
            if(editMode && editRecord) editRecord(data);
            else if (createRecord)
                createRecord(data, this)
        }else this.setState({loading : false});
    }
    render() {
        const {classes, editMode, data} = this.props;
        const {loading } = this.state;
        return (
            <div className={classes.root}>
                <FormLabel>New Family Record</FormLabel>
                <FormDisplay
                    formName="newFamilyForm"
                    getContext={context=>this.newFamilyFormContext = context}
                    formConfig={[
                        {name : "name", label : "Family Name", placeholder : "Family name", variant : "outlined", required : true}
                    ]}
                    formData={data}
                    footer={()=><div>
                        <HIRButton 
                            onClick={this.onClick.bind(this)}
                            loading={loading}>
                            {editMode ? "Edit" : "Create"} Family Record
                        </HIRButton>
                    </div>}
                    />
            </div>
        );
    }
}
_HIRNewFamily.propTypes = {
    classes : PropTypes.object.isRequired,
    createRecord : PropTypes.func,
    editMode : PropTypes.bool,
    data : PropTypes.object,
    editRecord : PropTypes.func,
};
export const HIRNewFamily = connect()(withStyles(style)(_HIRNewFamily));