import { headerStrings} from "./strings"
import { headerConstants } from "./constant";

export const headerReducer = (state={
    [headerStrings.appName] : "Inovate Operating System",
    [headerStrings.multipleApps] : true,
    [headerStrings.position] : "sticky",
}, action) => {
    const {type, payload} = action;
    switch(type){
        case headerConstants.SET_HEADER : 
            return {...state, ...payload};
        default : return {...state};
    }
}