import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import {FontAwesomeIcon} from '@fortawesome/react-fontawesome'
import { faFacebook, faInstagram, faLinkedin, faGooglePlus, faTwitter } from '@fortawesome/free-brands-svg-icons';
const style = theme => ({
    root: {
        display : "block",
        justifyContent : "center",
    },
    link : {
        margin : 5,
    }
})
class _SocialMedia extends Component {
    render() {
        const {classes, facebook, instagram, linkedIn, twitter} = this.props;
        return (
            <div className={classes.root}>
                {facebook && <a className={classes.link} href={"https://facebook.com/"+facebook}>
                    <FontAwesomeIcon size="2x" icon={faFacebook}/></a>}
                {instagram && <a className={classes.link} href={"https://instagram.com/"+instagram}>
                    <FontAwesomeIcon size="2x" icon={faInstagram}/></a>}
                {linkedIn && <a className={classes.link} href={"https://linkedin.com/mwlite/company/"+linkedIn}>
                    <FontAwesomeIcon size="2x" icon={faLinkedin}/></a>}
                {twitter && <a className={classes.link} href={"https://googleplus.com/"+twitter}>
                    <FontAwesomeIcon size="2x" icon={faTwitter}/></a>}
            </div>
        );
    }
}
_SocialMedia.propTypes = {
    classes : PropTypes.object.isRequired,
    instagram : PropTypes.string,
    linkedIn : PropTypes.string,
    twitter : PropTypes.string,
    facebook : PropTypes.string,
};
export const SocialMedia = withStyles(style)(_SocialMedia);