import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { IconButton, TextField, FormControl, Popover, List, ListItem, ListItemText, Button } from '@material-ui/core';
import { Settings, Cancel, Done } from '@material-ui/icons';
import { MyDialog } from '../../../MyDialog';
import MyArticleTextFieldStyleEditor from './MyArticleTextFieldStyleEditor/MyArticleTextFieldStyleEditor';


const style = theme => ({
    root: {
        display : "flex",
        alignItems : "flex-end",
    },
    iconBtn : {
        padding : 3,
    },
    cancel : {
        marginRight : 10
    }
})
class _MyArticleTextField extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : {
                name : props.name,
                value : ""
            },
            anchorEl : null,
            openDialog : false
        }
        const {data} = props;
        if(data) this.state.data = {
            ...this.state.data, ...data
        }
    }
    
    onChange = name => e => {
        const {data} = this.state;
        const {getStateData} = this.props;
        const value = e.target.value;
        data[name] = value;
        this.setState({data}, ()=>{
            getStateData && getStateData(this.state.data);
        });
    }
    menuControl = props => {
        const {name} = props;
        const {data} = this.state;
        switch(name){
            case "style" : 
                const {style} = data && data.props || {};
                return <MyArticleTextFieldStyleEditor
                    getContext={context=>this.styleContext=context}
                    data={style}
                />
            default : return null;
        }
    }
    addStyleProps(){
        const {getStateData} = this.props;
        const {data} = this.state;
        const {data : style} = this.styleContext && this.styleContext.state || {};
        if(data.props) data.props.style = style;
        else data.props = {style};
        this.setState({data, openDialog : false}, ()=>{
            getStateData && getStateData(this.state.data);
        });
    }
    render() {
        const {classes} = this.props;
        const {data, anchorEl, openDialog, menuName} = this.state;
        const styles = data.props && data.props.style;
        const SettingDisplay = this.menuControl.bind(this);
        return (
            <div className={classes.root}>
                <IconButton 
                    className={classes.iconBtn} 
                    onClick={(e)=>{
                        const anchorEl = e.target;
                        this.setState({anchorEl})
                    }}>
                    <Settings/>
                </IconButton>
                <TextField
                    fullWidth
                    margin="dense"
                    onChange={this.onChange("value")}
                    value={data && data.value || ""}
                    {...this.props.textFieldProps}
                    />
                <Popover
                    open={Boolean(anchorEl)}
                    anchorEl={anchorEl}
                    onClose={()=>this.setState({anchorEl : null})}
                    classes={this.props.popoverClasses}>
                    <List>
                        <ListItem button onClick={()=>this.setState({
                            menuName : "style", openDialog : true,
                            anchorEl : null,
                        })}>
                            <ListItemText 
                                primary="Style"
                                primaryTypographyProps={{
                                    style:{padding :5, fontSize : 12}
                                }}
                                />
                        </ListItem>
                    </List>
                </Popover>
                <MyDialog
                    open={openDialog}
                    close={()=>this.setState({openDialog : false})}>
                        <SettingDisplay 
                            name={menuName}
                        />
                        <div style={{marginTop : 20}}>
                            <Button
                                color="secondary"
                                variant="outlined"
                                onClick={()=>this.setState({openDialog : false})}
                                className={classes.cancel}
                                >
                                    <Cancel fontSize="small"/>
                                    Cancel
                                </Button>
                            <Button
                                color="primary"
                                variant="outlined"
                                onClick={this.addStyleProps.bind(this)}
                                >
                                    <Done fontSize="small"/>
                                    Continue
                                </Button>
                        </div>
                    </MyDialog>
            </div>
        );
    }
}


_MyArticleTextField.propTypes = {
    classes : PropTypes.object.isRequired,
    name : PropTypes.string,
    getStateData : PropTypes.func,
    popoverClasses : PropTypes.shape(Popover.propTypes),
    textFieldProps : PropTypes.shape(TextField.propTypes),
};
export const MyArticleTextField = withStyles(style)(_MyArticleTextField);
export {MyArticleTextField as default}