export const breadCrumbConstants = {
    BREAD_CRUMB : "BREAD_CRUMB",
    BREAD_CRUMB_ADD : "BREAD_CRUMB_ADD",
    BREAD_CRUMB_HIDE : "BREAD_CRUMB_HIDE",
    SET_PROPS : "SET_PROPS",
}
const initialState = {
    breadCrumb : [
        {name : "Dashboard", path: "/"}
    ],
    visible : true,
}
export const breadCrumbReducer = (state = initialState, action) => {
    const {type, payload} = action;
    switch(type){
        case breadCrumbConstants.BREAD_CRUMB : 
            return {...state, breadCrumb : payload};
        case breadCrumbConstants.BREAD_CRUMB_ADD :
            return {...state, breadCrumb : [...state.breadCrumb, ...payload]};
        case breadCrumbConstants.BREAD_CRUMB_HIDE : 
            return {...state, visible : false};
        case breadCrumbConstants.SET_PROPS : 
            return {...state, rootProps : state.rootProps ? 
                    {...state.rootProps, ...payload} : payload
                };
        default  : return {...state};
    }
}