import React, { PureComponent } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { Typography, withStyles, IconButton } from '@material-ui/core';
import { Close } from '@material-ui/icons';
const styles = theme => ({
    root : {
        position : "relative",
    },
    general : { 
        textAlign: "center",
        borderRadius : 5,
        padding : 20,
        paddingTop : 40
    },
    primary : {
        backgroundColor : "#80d8af",
        color : "#607d8b"
    },
    secondary : {
        backgroundColor : "#8e8971",
        color : "white"
    },
    closeBtn : {
        position : "absolute",
        top : 5,
        right : 10
    },
    closeIcon : {
        // color : colors.gray
    }
})
class _Info extends PureComponent {
    state = {
        close : false
    }
    closeInfo(callback){
        this.setState({close: true});
        callback && callback();
    }
    render() {
        const {classes, type, closable} = this.props;
        const {close} = this.state;
        return (
            !close && <div className={classes.root}>
                <Typography variant="subtitle2" className={
                    classNames(
                        classes.general,
                        classes[type],
                    )
                }>
                    {this.props.children}
                </Typography>
                {closable && <IconButton onClick={()=>this.closeInfo(this.props.onClose)} className={classes.closeBtn}>
                    <Close color="secondary" className={classes.closeIcon}/>
                </IconButton>}
            </div>
        );
    }
}
_Info.propTypes = {
    classes : PropTypes.object.isRequired,
    type : PropTypes.oneOf(["primary","secondary"]),
    closable : PropTypes.bool,
    onClose : PropTypes.func,
}
export const HighlightedInfo = withStyles(styles)(_Info);