import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { AppBar, Tabs, Tab } from '@material-ui/core';
import {colors} from '../../utils';


const style = theme => ({
    root : {
        marginTop : 50
    },
    rootNested : {

    },
    tabNavBar_root : {
        backgroundColor : colors.primary
    }
})
class _MyCustomTabs extends Component {
    constructor(props) {
        super(props);
        this.tabValues = Object.keys(this.props.tabs);
        this.state = {
            tabValue : this.tabValues && this.tabValues[0]
        }
        if(props.getInitialTabValue) props.getInitialTabValue(this.state.tabValue);
        if(props.getContext) props.getContext(this);
        this.handleTabChange = this.handleTabChange.bind(this);
    }
    handleTabChange(event, tabValue){
        this.setState({tabValue});
        this.props.getInitialTabValue(tabValue);
    }
    render() {
        const {classes, nested, position} = this.props;
        const {tabValue} = this.state;
        const root = nested ? classes.rootNested : classes.root;
        this.tabNames = Object.values(this.props.tabs);
        this.tabValues = Object.keys(this.props.tabs);
        return (
            <div className={root}>
                <AppBar
                    position={position || "fixed"} 
                    {...this.props.appBarProps}>
                    <Tabs 
                        indicatorColor="primary"
                        variant="scrollable"
                        value={tabValue} 
                        onChange={this.handleTabChange}
                        {...this.props.tabProps}>
                        {this.tabValues.map(
                            (item, index) => <Tab key={index} value={item} label={this.tabNames[index]}/>
                        )}
                    </Tabs>
                </AppBar>
            </div>
        );
    }
}


_MyCustomTabs.propTypes = {
    classes : PropTypes.object.isRequired,
    getInitialTabValue : PropTypes.func.isRequired,
    tabs : PropTypes.object.isRequired,
    nested : PropTypes.bool,
    getContext : PropTypes.func,
    appBarProps : PropTypes.object,
    tabProps : PropTypes.shape(Tabs.propTypes),
    position: PropTypes.oneOf(['fixed','absolute','sticky','static','relative']),
};



export const MyCustomTabs = connect()(withStyles(style)(_MyCustomTabs));