import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';


const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "column",
    },
    header : {
        fontSize : 18,
        fontWeight : "bold"
    },
    subtitle : {
        fontSize : 12,
        color : "gray"
    }
})
class _MyArticleDisplayHeader extends Component {
    render() {
        const {classes, name, value} = this.props;
        return (
            <div className={classes.root}>
                {name === "title" ? 
                    <div className={classes.header} {...this.props.textProps}>{value}</div> : 
                    <div className={classes.subtitle} {...this.props.textProps}>{value}</div>}
            </div>
        );
    }
}


_MyArticleDisplayHeader.propTypes = {
    classes : PropTypes.object.isRequired,
    name : PropTypes.string,
    value : PropTypes.string,
    textProps : PropTypes.object,
};
export const MyArticleDisplayHeader = withStyles(style)(_MyArticleDisplayHeader);
export {MyArticleDisplayHeader as default}