import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Carousel } from '../SiteComponent';


const style = theme => ({
    root: {
        backgroundSize : "cover",
        height : "100vh",
        width : "100vw",
        position : "relative"
    },
    overLay : {
        position : "absolute",
        minHeight : "100%",
        width : "100%",
        // backgroundColor : "black",
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
        justifyContent : "center",
        top : 0,
        zIndex : 110,
    },
    carousel: {
        height : "100vh"
    }
})
class _BackgroundImageDiv extends Component {
    state = {
        
    }
    componentDidMount() {
        const style = getComputedStyle(this.overLayRef);
        const height = style.height;
        this.setState({height})
    }
    render() {
        const {classes, overlayProps : _overlayProps} = this.props;
        const {style : overlayStyle, ...overlayProps} = _overlayProps || {};
        return (
            <div className={classes.root}>
                <Carousel
                    interval={5000}
                    hideOverlay
                    classes={{
                        root : classes.carousel
                    }}
                    commonProps={{
                        style : {
                            height : this.state.height
                        }
                    }}
                    items={[
                        {name : 1, src : this.props.imageUrl},
                    ]}
                    baseUrl=""
                    />
                <div 
                    style={{
                        ...overlayStyle, 
                        background : this.props.tintColor, 
                        height : this.state.height
                    }}
                    className={classes.overLay} 
                    ref={e=>this.overLayRef=e}
                    {...overlayProps}>
                        {this.props.children}
                </div>
            </div>
        );
    }
}


_BackgroundImageDiv.propTypes = {
    classes : PropTypes.object.isRequired,
    imageUrl : PropTypes.string,
    tintColor : PropTypes.string,
};
export const BackgroundImageDiv = withStyles(style)(_BackgroundImageDiv);
export {BackgroundImageDiv as default}