import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { errorNotice, MyTable } from '../../../utils';
import { hirSettingStrings, hirSettingActions } from '../../../HIRSettings';
import { TableCell, FormControl, InputLabel, Select, MenuItem, TextField, IconButton, Typography, FormGroup, FormHelperText, FormLabel, RadioGroup, FormControlLabel, Radio, Grid } from '@material-ui/core';
import { AccountBalance, AccountBalanceWallet, Add, Delete } from '@material-ui/icons';
import { appActions, alertAction } from '../../../../../actions';
import { HIRButton } from '../../../Includes';

class PaymentAmount extends Component{
    constructor(props) {
        super(props);
        this.state ={
            amount : ""
        }
        props.getContext(this);
    }
    onChange = name => e => {
        const value = e.target.value;
        this.setState({[name] : value});
    }
    render(){
        const {amount, show} = this.state;
        return <FormGroup>
            {show && <FormHelperText>{Number(amount).toLocaleString()}</FormHelperText>}
            <TextField
                onFocus={() => this.setState({show : true})}
                onBlur={() => this.setState({show : false})}
                style={{
                    width : "100%"
                }}
                type="number"
                margin="normal"
                placeholder="Amount"
                label="Amount"
                variant="outlined"
                value={amount}
                onChange={this.onChange("amount")}
            />
        </FormGroup>
    }
}
const style = theme => ({
    root: {
    },
    btn : {
        marginTop : 20,
    },
    cell : {
        padding : 5,
    }, 
    creditWallet : {
        display : "flex",
    }
})
class _HIRMultiplePayment extends Component {
    constructor(props) {
        super(props);
        this.state = {
            revenueType : "",
            amount : "",
            paymentList : [
                
            ],
            loading : false,
        }
        const {editMode, paymentData} = props;
        if(editMode && paymentData){
            if(paymentData && paymentData.accountAction)
                this.state.accountAction = paymentData.accountAction
        }
    }
    onChange = name => e => {
        const value = e.target.value;
        this.setState({[name] : value});
    }
    addPayment(){
        const {dispatch} = this.props;
        const {revenueType, paymentList} = this.state;
        const amount = this.amountContext.state.amount
        if(!String(revenueType).trim() || !String(amount).trim()){
            appActions.showSnackbar(
                alertAction.error("Empty field!")
            )(dispatch);
            return;
        }
        paymentList.push({revenueType, amount : parseInt(amount)});
        this.setState({paymentList});
    }
    deleteRow = row => ()  => {
        const {paymentList} = this.state;
        const index = paymentList.findIndex(item=>JSON.stringify(item)===JSON.stringify(row));
        paymentList.splice(index, 1);
        this.setState({paymentList});
    }
    cellMapFormat = total=> ({row, cellMap}) => {
        const {
            [hirSettingStrings.settings] : settings,
            classes
        } = this.props;
        const {revenueType} = this.state;
        if(row.total){
            switch(cellMap){
                case "description" : return <TableCell className={classes.cell}>
                    <strong>Total</strong>
                </TableCell>
                case "amount" : return <TableCell className={classes.cell}>
                    <strong>N {Number(total).toLocaleString()}</strong>
                </TableCell>
                default : return <TableCell className={classes.cell}>

                </TableCell>
            }
        }
        else if(row.new){
            switch(cellMap){
                case "action" : return <TableCell className={classes.cell}>
                    <IconButton onClick={this.addPayment.bind(this)}>
                        <Add style={{color : "green"}}/>
                    </IconButton>
                </TableCell>
                case "amount" : 
                    return <TableCell className={classes.cell}>
                        <PaymentAmount
                            getContext={context=>this.amountContext = context }/>
                    </TableCell>
                case "description" : 
                    let revenueOptions = [];
                    if(settings){
                        const revenue = settings.find(item=>item.name==="revenue");
                        revenueOptions = revenue ? revenue.values : [];                        
                    }
                    return <TableCell className={classes.cell}>
                        <FormControl style={{
                                width : "100%"
                            }}>
                                <InputLabel htmlFor="revenueTypeSelection">Description</InputLabel>
                                <Select
                                    
                                    inputProps={{
                                        id : "revenueTypeSelection",
                                        style : {
                                            width : "100%"
                                        }
                                    }}
                                    variant="outlined"
                                    label="Description"
                                    placeholder="Description"
                                    value={revenueType}
                                    onChange={this.onChange("revenueType")}>                                    
                                        {revenueOptions && revenueOptions.map((item, index)=>
                                            <MenuItem key={index} value={item.name}>
                                                {item.value}
                                        </MenuItem>)}
                                    </Select>
                            </FormControl>                    
                        </TableCell>
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }else{
            switch(cellMap){
                case "action" : 
                    return <TableCell className={classes.cell}>
                        <Delete color="secondary" fontSize="small" onClick={this.deleteRow(row)}/>
                    </TableCell>
                case "description" : 
                    let iValue = row[cellMap];
                    if(settings){
                        iValue = hirSettingActions.getSettingValue(settings, "revenue", row.revenueType)
                    }
                    return <TableCell className={classes.cell}>
                        {iValue}
                    </TableCell>
                case "amount" : return <TableCell className={classes.cell}>
                    {Number(row[cellMap]).toLocaleString()}
                </TableCell>
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }
    }
    postPayment = amount => () => {
        const {paymentList, actionDate, accountAction} = this.state;
        const {dispatch, postPayment, editMode, editPayment, paymentData, patient} = this.props;
        if(paymentList.length === 0){
            appActions.showSnackbar(
                alertAction.error("No payment added")
            )(dispatch);
        }
        const data = {paymentList, amount};
        if(accountAction){
            const {credit} = patient || {};
            if(accountAction === "useCredit" && !editMode && (!credit || parseInt(amount) > credit)) 
                return errorNotice("Insuffient credit!", dispatch);
            else if(accountAction === "addToDebt" && !editMode && credit && credit > amount)
                return errorNotice("You can't use debt record with sufficient credit", dispatch);
            else if(editMode){
                const {amount : oldAmount} = paymentData || {};
                if(!oldAmount) return errorNotice("Something went wrong!", dispatch);
                if(amount > oldAmount){
                    const diffAmount = amount - oldAmount;
                    if(credit < diffAmount)
                        return errorNotice("Insufficient Credit", dispatch)
                }

            }
            data.accountAction = accountAction
        }
        this.setState({loading : true});
        if(data){
            if(actionDate) data.actionDate = actionDate;
            if(editMode && editPayment)
                editPayment(data, this);
            else if(postPayment)
                postPayment(data, this);
        }else this.setState({loading : false});
    }
    onChangeDate(e){
        const actionDate = e.target.value;
        this.setState({actionDate});
    }
    options = [
        {_id : "none", name : "None"},
        {_id : "useCredit", name : "Use Credit"},
        {_id : "addToDebt", name : "Add to Debit"}
    ]
    handleRadio = e => {
        const value = e.target.value;
        this.setState({accountAction : value === "none" ? null : value});
    }
    render() {
        const {classes, patient, editMode} = this.props;
        const {paymentList, loading, accountAction} = this.state;
        let lastName, firstName; 
        if(patient){
            const {myProfile} = patient;
            lastName = myProfile.lastName;
            firstName = myProfile.firstName;
        }
        let total = 0;
        if(paymentList){
            for (let i = 0; i < paymentList.length; i++) {
                const list = paymentList[i];
                total += Number(list.amount);
            }
        }
        const {credit, debt} = patient || {};
        let newPaymentList = paymentList ? [...paymentList, {new : true}, {total : true}] : [{new : true}, {total : true}];
        return (
            <div className={classes.root}>
                <Grid container>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <div className={classes.creditWallet}>
                            <div style={{width : "30%", borderRight : "solid 1px", display : "flex", justifyContent : "flex-end", padding : 10}}>
                                <AccountBalanceWallet/>
                            </div>
                            <div style={{padding : 10, display : "flex", flexDirection : "column"}}>
                                <strong>Credit</strong>
                                <span>{Number(credit || 0).toLocaleString()}</span>
                            </div>
                        </div>
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <div className={classes.creditWallet}>
                            <div style={{width : "30%", borderRight : "solid 1px", display : "flex", justifyContent : "flex-end", padding : 10}}>
                                <AccountBalance/>
                            </div>
                            <div style={{padding : 10, display : "flex", flexDirection : "column"}}>
                                <strong>Debts</strong>
                                <span>{Number(debt || 0).toLocaleString()}</span>
                            </div>
                        </div>
                    </Grid>
                </Grid>
                <div style={{marginTop : 20}}/>
                <Typography paragraph>{lastName && "New Payment for "+lastName+", "+firstName}</Typography>
                <div style={{marginBottom : 20}}>
                    <TextField
                        label="Date"
                        type="date"
                        onChange={this.onChangeDate.bind(this)}
                    />
                    <FormHelperText>Date : Leave this empty to use today's date!</FormHelperText>
                </div>
                <MyTable
                    elevation={0}
                    header={["Description", "Amount", "Action"]}
                    dataMap={["description", "amount", "action"]}
                    data={newPaymentList}
                    CellMap={this.cellMapFormat(total)}
                    />
                <FormControl fullWidth style={{padding : 10}}>
                    <Fragment>
                        <FormLabel>Account Actions</FormLabel>
                        <RadioGroup
                            onChange={this.handleRadio.bind(this)}
                            value={accountAction}
                            name={"accountAction"}
                            aria-label={"accountAction"}
                        >
                            {this.options.map((item, index)=>{
                                return <FormControlLabel
                                disabled={editMode}
                                key={index}
                                label={<span>{item.name}</span>}
                                value={item._id}
                                control={<Radio size="small"/>}/>
                            })}
                        </RadioGroup>
                    </Fragment>
                    <FormHelperText></FormHelperText>
                </FormControl>
                <HIRButton 
                    classes={{
                        btn : classes.btn
                    }}
                    loading={loading}
                    onClick={this.postPayment(total)}>
                    Post Payment
                </HIRButton>
            </div>
        );
    }
}


_HIRMultiplePayment.propTypes = {
    classes : PropTypes.object.isRequired,
    patient : PropTypes.object,
    postPayment : PropTypes.func,
    editMode : PropTypes.bool,
    paymentData : PropTypes.object,
    editPayment : PropTypes.func,
};
const mapStateToProps = ({hirSettingReducer}) => ({
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings]
})


export const HIRMultiplePayment = connect(mapStateToProps)(withStyles(style)(_HIRMultiplePayment));
export {HIRMultiplePayment as default}