import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { ProfilePicture } from '../../../ProfilePicture';


const style = theme => ({
    root: {
    },
    img : {
        borderRadius : 0,
    }
})
class _MyArticleImage extends Component {
    render() {
        const {classes} = this.props;
        return (
            <div className={classes.root}>
                <ProfilePicture
                    classes={{
                        img : classes.img,
                    }}
                    {...this.props.profilePictureProps}
                />
            </div>
        );
    }
}


_MyArticleImage.propTypes = {
    classes : PropTypes.object.isRequired,
    profilePictureProps : PropTypes.shape(ProfilePicture.propTypes)
};

export const MyArticleImage = withStyles(style)(_MyArticleImage);
export {MyArticleImage as default}