export * from './MyTable'
export * from './EditableCellMapFormat';
export const getEditableCellMapFormatNewValues = (context) => {
    const nameValue={};
    if(context) Object.entries(context).map(item=>{
        const name = item[0];
        const component = item[1];
        nameValue[name] = component && component.state && component.state.data && 
            component.state.data.value;
    });
    return nameValue;
}