import React, { PureComponent, Fragment } from 'react';
import {connect} from 'react-redux';
import MainStage from '../MainStage/MainStage';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { Header, headerStrings } from '../Header';
import { withStyles, withTheme, IconButton, Fade} from '@material-ui/core';
import { drawerWidth } from '../Header/Drawer';
import { ThemeProvider } from '@material-ui/styles';
import { screenStrings } from './strings';
import {ScreenSetupControl} from './ScreenSetupControl';
import { Close } from '@material-ui/icons';
import { screenActions } from './actions';
const styles = theme => ({
    root : {
        minHeight : "100vh",
        position : "relative",
        [theme.breakpoints.up("sm")] : {
            marginLeft : drawerWidth,
        }
    },
    componentRoot : {
        margin : 10,
    },
    notificationContainer : {
        minHeight : 50,
        position : "relative",
        backgroundColor : "yellow",
        display : "flex",
        justifyContent : "center",
        alignItems : "center",
        fontSize : 12,
        [theme.breakpoints.down("sm")] : {
            fontSize : 11
        }
    },
    notificationCloseBtnOverlay : {
        display : "flex",
        position : "absolute",
        zIndex : 100,
        top : 0,
        right : 0,
        padding : 5,
    },
    ADContainerOverlay : {
        backgroundColor : "#808080e0",
        position : "fixed",
        bottom : 10,
        right : 10,
        zIndex : 100,
        height : 150,
        width : 200,
        borderRadius : 5,
    },
    ADBtnOverlay : {
        position : "absolute",
        right : 0,
        top : 0,
        zIndex : 100,
    },
    adBtn : {
        color : "red",
        padding : 2,
        border : "solid 1px"
    }
});
class _Screen extends PureComponent {
    constructor(props) {
        super(props);
        this.componentTheme = {
            ...props.theme, 
            colors : props.appTheme
        }
        this.state= {
            notifAnimationStart : false, 
            notifIndex : 0,
            ADIndex : 0,
        }
    }
    startNotifAnimation(name, length = 0, duration=2000){
        let {[name] : animIndex} = this.state;
        if(!length || length === 0) return;
        return setInterval(() => {
            if(animIndex + 1 === length) 
                animIndex = 0;
            else animIndex++;
            this.setState({[name] : animIndex})
        }, duration);
    }
    componentWillUnmount(){
        clearInterval(this.notifInterval);
        clearInterval(this.ADInterval);
    }
    DisplayTopNotification(props){
        const {classes, notifInterval, containerProps, component : Component, closable, dispatch} = props;
        return <div className={classNames("animated","fadeIn", classes.notificationContainer)} 
            {...containerProps}>
                <Component/>
                {closable && <div className={classes.notificationCloseBtnOverlay}>
                    <IconButton onClick={()=>{
                        screenActions.payload({
                            [screenStrings.showNotification] : false
                        })(dispatch);
                        clearInterval(notifInterval);
                    }}>
                        <Close fontSize="small"/>
                    </IconButton>
                </div>}
            </div>
    }
    ADDisplay(props){        
        const {classes, ADInterval, containerProps, component : Component, closable, dispatch} = props;
        return <div className={classNames(classes.ADContainerOverlay)} {...containerProps}>
            <Component  style={{height : 150, width : 200}}/>
            {closable && <div className={classes.ADBtnOverlay}>
                <IconButton className={classes.adBtn} onClick={()=>{
                    screenActions.payload({
                        [screenStrings.showAD] : false
                    })(dispatch);
                    clearInterval(ADInterval);
                }}>
                    <Close fontSize="small"/>
                </IconButton>
            </div>}
        </div>
    }
    render() {
        const {
            classes, drawer, fullScreen, appTheme, headerProps, drawerProps,
            component : Component, 
            [screenStrings.setup] : setup,
            [screenStrings.setupComponent] : SetupComponent,
            [screenStrings.setupQuery] : setupQuery,
            [screenStrings.setupQueryPass] : setupQueryPass,
            [screenStrings.showNotification] : showNotification,
            [screenStrings.notificationComponents] : notificationComponents,
            [screenStrings.notificationPosition] : notificationPosition = "top",
            [screenStrings.notificationContainerProps] : notificationContainerProps,
            [screenStrings.notificationClosable] : notificationClosable,
            [screenStrings.showAD] : showAD,
            [screenStrings.ADPosition] : ADPosition,
            [screenStrings.ADComponents] : ADComponents,
            [screenStrings.ADContainerProps] : ADContainerProps,
            [screenStrings.ADClosable] : ADClosable,
            ...otherProps
        } = this.props;
        let search, searchArray, searchObject, allow;
        const {notifAnimationStart, notifIndex, ADStart, ADIndex} = this.state;
        if(showNotification && notificationComponents && !notifAnimationStart){
            this.notifInterval = this.startNotifAnimation("notifIndex", notificationComponents.length);
            this.state.notifAnimationStart = true;
        }
        if(showAD && ADComponents && !ADStart){
            this.ADInterval = this.startNotifAnimation("ADIndex", ADComponents.length);
            this.state.ADStart = true;
        }
        const NotificationComponent = notificationComponents && notificationComponents[notifIndex],
        ADComponent = ADComponents && ADComponents[ADIndex];
        if(setup){
            search = this.props.location.search;
            searchObject = {};
            if(search){
                search =String(search).replace("?", "");
                searchArray = String(search).split("&").map(item=>item.split("="));
                if(searchArray) for (let i = 0; i < searchArray.length; i++) {
                    const s = searchArray[i];
                    searchObject[s[0]] = s[1];         
                }
            }
            allow = searchObject[setupQuery] === setupQueryPass;
        }
        return (
            <div className={drawer && !fullScreen ? classes.root : ""} {...this.props.containerProps}>
                {showNotification && NotificationComponent && 
                notificationPosition === "top" && <this.DisplayTopNotification
                    dispatch={this.props.dispatch}
                    component={NotificationComponent}
                    classes={classes}
                    containerProps={notificationContainerProps}
                    closable={notificationClosable}
                    notifInterval={this.notifInterval}
                />}
                {showAD && ADComponent && <this.ADDisplay
                    position={ADPosition}
                    component={ADComponent}
                    classes={classes}
                    containerProps={ADContainerProps}
                    closable={ADClosable}
                    notifInterval={this.ADInterval}
                    dispatch={this.props.dispatch}
                />}
                <Header 
                    rootProps={{                    
                        style: {
                            backgroundColor : appTheme ? appTheme.headerBg || appTheme.primary : null,
                        }
                    }}
                    drawerProps={{
                        color : appTheme ? appTheme.backgroundTypo : null,
                        bgColor : appTheme ? appTheme.drawerBg : null,
                        ...drawerProps,
                    }}
                    iconProps={{
                        style : {color : appTheme ? appTheme.backgroundTypo : null}
                    }} 
                    subheaderMenuProps={{
                        [headerStrings.offsetHeight] : 78,
                    }}
                    {...headerProps}/>
                {setup && SetupComponent && <SetupComponent display={!allow}/>}
                {(!setup || (setup && SetupComponent && allow)) &&
                    <MainStage appTheme={appTheme}>
                        <ThemeProvider theme={this.componentTheme}>
                            <Component classes={{
                                root : classes.componentRoot
                            }} {...otherProps}/>
                        </ThemeProvider>
                    </MainStage>}
                {setup && allow && <div>
                    <ScreenSetupControl location={this.props.location}/>
                </div>}
            </div>
        )
    }
}
_Screen.propTypes = {
    containerProps : PropTypes.object,
    drawerProps : PropTypes.object,
}
const mapStateToProps = ({screenReducer, headerReducer}) => ({
    ...screenReducer, 
    drawer : headerReducer[headerStrings.drawer], 
    fullScreen : headerReducer[headerStrings.fullScreen],
})
export const Screen = connect(mapStateToProps)(withStyles(styles)(withTheme(_Screen)));
export {Screen as default};