import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Button } from '@material-ui/core';
import { ArrowBackIos, ArrowForwardIos } from '@material-ui/icons';
import { drawerWidth } from '../../_Header/Drawer';
import { screenStrings } from '../strings';


const style = theme => ({
    root : {
    },
    prevBtnContainer: {
        position : "fixed",
        zIndex : 120,
        bottom : 20,
        left : 20+drawerWidth,
    },
    nextBtnContainer : {
        position : "fixed",
        zIndex : 120,
        bottom : 20,
        right : 20,
    }
})
class _ScreenSetupControl extends Component {
    render() {
        const {
            classes,
            [screenStrings.setupNavigatorLinks] : links,
            [screenStrings.setupNavigator] : setupNavigator,
            [screenStrings.setupQuery] : setupQuery,
            [screenStrings.setupFinishBtn] : FinishBtn,
            location,
        } = this.props;
        const {pathname} = location || {};
        const linkIndex = links && links.findIndex(item=>String(pathname).includes(item));
        return (
            <div className={classes.root}>
                {linkIndex !== 0 && <div className={classes.prevBtnContainer}>
                    <Button
                        onClick={()=>setupNavigator && setupNavigator(links[linkIndex-1]+"?"+setupQuery+"=1")}
                        color="secondary">
                            <ArrowBackIos fontSize="small"/>
                            Previous
                        </Button>
                </div>}
                <div className={classes.nextBtnContainer}>
                    {links && linkIndex !== links.length - 1 ? <Button
                        onClick={()=>setupNavigator && setupNavigator(links[linkIndex+1]+"?"+setupQuery+"=1")}
                        color="primary">
                        Next
                        <ArrowForwardIos fontSize="small"/>
                    </Button> : (FinishBtn && <FinishBtn/>)}
                </div> 
            </div>
        );
    }
}


_ScreenSetupControl.propTypes = {
    classes : PropTypes.object.isRequired,
    location : PropTypes.object,
};
const mapStateToProps = ({screenReducer}) => ({
    [screenStrings.setupNavigatorLinks] : screenReducer[screenStrings.setupNavigatorLinks],
    [screenStrings.setupNavigator] : screenReducer[screenStrings.setupNavigator],
    [screenStrings.setupQuery] : screenReducer[screenStrings.setupQuery],
    [screenStrings.setupFinishBtn] : screenReducer[screenStrings.setupFinishBtn],
})
export const ScreenSetupControl = connect(mapStateToProps)(withStyles(style)(_ScreenSetupControl));
export {ScreenSetupControl as default}