import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {Link} from 'react-router-dom';
import {withStyles} from '@material-ui/core/styles';
import { Card, CardMedia, CardHeader, CardContent, Typography, CardActions, Button } from '@material-ui/core';
const style = theme => ({
    root: {
        marginTop : 100,
        [theme.breakpoints.up("sm")] : {
            margin : 100,
        },
        [theme.breakpoints.up("md")] : {
            margin : "100px 200px",
        },
    },
    cardMedia : {
        height : 200
    },
    cardHeader : {

    },
    editBtn : {},
    cardContent : {},
    title : {},
    saveBtn : {},
})
class _Article extends Component {

    render() {
        const {
            classes, header, body, date, name,
            src, editable, baseUrl, footer : Footer} = this.props;
            if(editable && (!this.props.editBtnHandler && !this.props.editLink)) 
                throw("No handle edit handler (editBtnHandler or editLink)");
        return (
            <Card elevation={0} className={classes.root}>
                {src && <CardMedia
                    image={baseUrl ? baseUrl+src: src}
                    className={classes.cardMedia}/>}
                <CardHeader
                    title={header}
                    subheader={date && new Date(date).toLocaleString()}
                    className={classes.cardHeader}/>

                <CardContent 
                    className={classes.cardContent}>
                    {body && body.map((item, index)=>
                        <Typography 
                            key={index}
                            paragraph 
                            className={classes.textItem}>
                                {item}
                            </Typography>)}
                </CardContent>
                {Footer && <Footer context={this}/>}
                {editable && <CardActions>
                    {this.props.editBtnHandler ? 
                        <Button 
                            className={classes.editBtn} 
                            color="primary"
                            onClick={this.props.editBtnHandler && 
                                this.props.editBtnHandler(name)}>Edit</Button> :
                        <Link to={this.props.editLink}>Edit</Link>}
                </CardActions>}
            </Card>
        );
    }
}
_Article.propTypes = {
    classes : PropTypes.object.isRequired,
    header : PropTypes.string,
    body : PropTypes.oneOfType([PropTypes.string, PropTypes.array]),
    date : PropTypes.object,
    src : PropTypes.string,
    baseUrl : PropTypes.string,
    editable : PropTypes.bool,
    editLink : PropTypes.oneOfType([PropTypes.string, PropTypes.array]),
    editBtnHandler : PropTypes.func,
    footer : PropTypes.func,
};
export const Article = withStyles(style)(_Article);