export const hirUserStrings = {
    users : "users",
}
export const hirUserConstant = {
    SET_HIR_USER : "SET_HIR_USER",
}
export const hirUserReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case hirUserConstant.SET_HIR_USER :
            return {...state, ...payload};
        default : return state;
    }
}