import { hirUtilConstants, hirUtilStrings } from "./config";
import { hirUtilServices } from "./services";
import { _storeData, errorNotice } from "../../../utils";
import { store } from "../../../helpers";
import { hirMenuItem2, hirMenuItem } from "../menuItems";
import { headerStrings, headerActions } from "../../../includes";
export const hirUtilActions = payload => dispatch => dispatch({
    type : hirUtilConstants.SET_UTIL,
    payload 
});

export const hirActions = {
    getUser : callback => dispatch => {
        hirUtilServices.getUser((done, result, message)=>{
            if(done){
                userInitialisation(result, dispatch);
            }
            if(callback) callback(done, result, message);
        })
    },
    loging : (email, password, callback) => dispatch => {
        hirUtilServices.login(email, password, (done, result, message)=>{
            if(done){
                userInitialisation(result, dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    logout : () => {
        const reducer = store.getState().hirUtilReducer;
        hirUtilActions({
            [hirUtilStrings.myProfile] : null
        })(store.dispatch);
        headerActions({
            [headerStrings.menuItems] : hirMenuItem
        })(store.dispatch);
        localStorage.removeItem(reducer[hirUtilStrings.tokenAlias]);
        localStorage.removeItem(reducer[hirUtilStrings.userAlias]);
    },
}
const userInitialisation = ({_id, myProfile}, dispatch) => {
    const reducer = store.getState().hirUtilReducer;
    _storeData(reducer[hirUtilStrings.tokenAlias], myProfile.token);
    _storeData(reducer[hirUtilStrings.userAlias], _id);
    hirUtilActions({
        [hirUtilStrings.myProfile] : myProfile,
    })(dispatch);
    if(myProfile && [0, 11].indexOf(myProfile.privilege) !== -1){
        headerActions({
            [headerStrings.menuItems] : hirMenuItem2
        })(dispatch);
    }
}