import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { FormLabel, Grid, ListItem, ListItemText, List, TextField, FormGroup, FormControlLabel, Radio, RadioGroup, InputLabel } from '@material-ui/core';
import { SketchPicker } from "react-color";

const style = theme => ({
    root: {
    }
})
class _MyArticleTextFieldStyleEditor extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : {
    
            }
        }
        this.styleItems = [
            {id : "color", name : "Color", description : "Change text color"},
            {id : "textAlign", name : "Text Align", description : "Adjust text's horizontal alignment", options : ["left", "center", "right"]},
            {id : "fontSize", name : "Font Size", description : "Adjust text font size", type : "number"},
        ]
        for (let i = 0; i < this.styleItems.length; i++) {
            const {id} = this.styleItems[i];
            this.state.data[id] = ""
        }
        const {data, getContext} = props;
        if(data) this.state.data = {
            ...this.state.data, ...data
        }
        if(getContext) getContext(this);
    }
    optionControl = props => {
        const {id, name, options, type} = props.option || {};
        const {data} = this.state;
        switch(id){
            case "color" : return <FormGroup>
                <TextField
                fullWidth
                margin="dense"
                label={name}
                value={data[id] && data[id].hex}
                onChange={e=>{
                    const value = e.target.value;
                    this.setState(
                        state=>({ data : {...state.data, [id] : value}})
                    )
                }}
                />
                <SketchPicker 
                    width="100%"
                    color={data[id]}
                    onChangeComplete={color=>this.setState(
                        state=>({ data : {...state.data, [id] : color}})
                    )}/>
            </FormGroup>
            case "textAlign" : return <RadioGroup>
                <InputLabel>{name}</InputLabel>
                {options && options.map((item, index)=>{
                    return <FormControlLabel
                        key={index}
                        checked={data[id]===item}
                        onChange={(e)=>{
                            const value = e.target.value;
                            this.setState(
                                state=>({ data : {...state.data, [id] : value}})
                            )
                        }}
                        control={<Radio size="small" value={item}/>}
                        label={item}
                        />
                })}
            </RadioGroup>;
            case "fontSize" : return <TextField
                    fullWidth
                    margin="dense"
                    label={name}
                    type={type}
                    placeholder={name}
                    onChange={e=>{
                        const value = e.target.value;
                        this.setState(
                            state=>({ data : {...state.data, [id] : parseInt(value)}})
                        )
                    }}
                    value={data[id]}
                />
            default : return null;
        }
    }
    render() {
        const {classes} = this.props;
        const {selectedOption} = this.state; 
        return (
            <div className={classes.root}>
                <FormLabel>Text Style</FormLabel>
                <div style={{marginTop : 20}}>
                    <Grid container spacing={2}>
                        <Grid item xs={6} sm={6} md={6} lg={6} xl={6}>
                            <List>
                                {this.styleItems.map((item, index)=>
                                <ListItem
                                    key={index}
                                    button
                                    onClick={()=>this.setState({selectedOption : item})}
                                >
                                    <ListItemText 
                                        primary={item.name}
                                        primaryTypographyProps={{style : {fontSize :12}}}
                                        secondary={item.description}
                                        secondaryTypographyProps={{style : {fontSize :10}}}
                                        />
                                </ListItem>)}
                            </List>
                        </Grid>
                        <Grid item xs={6} sm={6} md={6} lg={6} xl={6}>
                            {this.optionControl({option :selectedOption})}
                        </Grid>
                    </Grid>
                </div>
            </div>
        );
    }
}


_MyArticleTextFieldStyleEditor.propTypes = {
    classes : PropTypes.object.isRequired,
    data : PropTypes.object,
};
export const MyArticleTextFieldStyleEditor = withStyles(style)(_MyArticleTextFieldStyleEditor);
export {MyArticleTextFieldStyleEditor as default}